{"command": "# Let me just create a clean approach - generate a requirements.txt from the pyproject
# and use pip to install everything

# First, let's see what the actual dependencies are
python3 -c "
import tomllib
with open('pyproject.toml', 'rb') as f:
    data = tomllib.load(f)
    deps = data['tool']['poetry']['dependencies']
    print('Main dependencies:')
    for k, v in deps.items():
        if k == 'python':
            continue
        if isinstance(v, dict):
            print(f'  {k}: {v.get(\"version\", \"*\")}')
        elif isinstance(v, list):
            print(f'  {k}: {v}')
        else:
            print(f'  {k}: {v}')

    dev_deps = data['tool']['poetry']['dev-dependencies']
    print('\\nDev dependencies:')
    for k, v in dev_deps.items():
        if isinstance(v, dict):
            print(f'  {k}: {v.get(\"version\", \"*\")}')
        else:
            print(f'  {k}: {v}')
"
"}

